              "javascript": "// Espejo de JavaScript del ejemplo del mÃ³dulo Java actualizado.\n// Esto conserva los mismos puntos de control de instrucciÃ³n y resultados visibles.\n(function runModuleDemo() {\n    const moduleTitle = \"Introduction to Coding â€¢ From Early Computing to Modern Development\";\n    const moduleDescription = \"Comienza aquÃ­ si eres nuevo. Este mÃ³dulo explica quÃ© es la codificaciÃ³n, de dÃ³nde viene, quÃ© carreras existen, cÃ³mo elegir su camino y su primer idioma, cÃ³mo configurar su entorno y los hÃ¡bitos bÃ¡sicos que hacen que los principiantes tengan Ã©xito.\";\n    const topics = [\"Â¿QuÃ© es la codificaciÃ³n?\", \"Una breve historia de la programaciÃ³n\", \"CÃ³mo el cÃ³digo se convierte en software en ejecuciÃ³n\", \"CÃ³mo encaja la pila de software\", \"Trayectorias profesionales en tecnologÃ­a\", \"Elegir su camino de aprendizaje\"];\n    const javaSignals = [\"=== Programming Timeline ===\"];\n\n    // 1) Contexto del mÃ³dulo de alto nivel\n    console.log(\"MÃ³dulo en ejecuciÃ³n: \" + moduleTitle);\n    console.log(moduleDescription);\n\n    // 2) Lista de verificaciÃ³n de temas para una cobertura conceptual completa\n    console.log(\"Lista de verificaciÃ³n de temas:\");\n    topics.forEach((topic) => console.log(\"- \" + topic));\n\n    // 3) Marcadores de paridad de Java para alinearse con la muestra canÃ³nica de Java\n    console.log(\"Puntos de control de paridad del ejemplo de Java:\");\n    javaSignals.forEach((line) => console.log(\"* \" + line));\n\n    console.log(\"Muestra de paridad de JavaScript completada.\");\n})();\n"
