          "java": "/*\n * Ãrboles binarios: muestra guiada completa\n * Objetivos de cobertura:\n * 1) Recorrido del Ã¡rbol\n * 2) Ãrboles de bÃºsqueda binaria\n * 3) Altura del Ã¡rbol\n * 4) Problemas de ruta\n * 5) ConstrucciÃ³n de Ã¡rboles\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\n// Recorridos de Ã¡rboles binarios e inserciÃ³n en Java.\nclass TreeNode {\n    int value;\n    TreeNode left;\n    TreeNode right;\n\n    TreeNode(int value) {\n        this.value = value;\n    }\n}\n\npublic class BinaryTree {\n    TreeNode root;\n\n    public void insert(int value) {\n        root = insertRecursive(root, value);\n    }\n\n    private TreeNode insertRecursive(TreeNode node, int value) {\n        if (node == null) {\n            return new TreeNode(value);\n        }\n        if (value < node.value) {\n            node.left = insertRecursive(node.left, value);\n        } else if (value > node.value) {\n            node.right = insertRecursive(node.right, value);\n        }\n        return node;\n    }\n\n    public void inorder(TreeNode node) {\n        if (node == null) return;\n        inorder(node.left);\n        System.out.print(node.value + \" \");\n        inorder(node.right);\n    }\n\n    public void levelOrderTraversal() {\n        java.util.Queue<TreeNode> queue = new java.util.LinkedList<>();\n        queue.offer(root);\n        while (!queue.isEmpty()) {\n            TreeNode current = queue.poll();\n            System.out.print(current.value + \" \");\n            if (current.left != null) queue.offer(current.left);\n            if (current.right != null) queue.offer(current.right);\n        }\n    }\n\n    public static void main(String[] args) {\n        BinaryTree bst = new BinaryTree();\n        int[] values = {8, 3, 10, 1, 6, 14, 4};\n        for (int value : values) {\n            bst.insert(value);\n        }\n        System.out.print(\"En orden: \");\n        bst.inorder(bst.root); // 1 3 4 6 8 10 14\n        System.out.print(\"\\nOrden de niveles: \");\n        bst.levelOrderTraversal();\n    }\n}",
