              "java": "/*\n * Montones y colas prioritarias: muestra guiada completa\n * Objetivos de cobertura:\n * 1) MontÃ³n mÃ­nimo\n * 2) MontÃ³n mÃ¡ximo\n * 3) Operaciones de montÃ³n\n * 4) Amontonar\n * 5) Colas prioritarias\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\nimport java.util.*;\n\npublic class HeapsTopic5Set {\n    // Deterministic helper so learners can verify output after each edit.\n    static int guidedComputation(int seed) {\n        int total = 0;\n        for (int step = 1; step <= 5; step++) {\n            total += seed * step;\n            System.out.println(\"Step \" + step + \" -> running total: \" + total);\n        }\n        return total;\n    }\n\n    static void printTopicChecklist(List<String> topics) {\n        System.out.println(\"Lista de verificaciÃ³n de temas:\");\n        for (int i = 0; i < topics.size(); i++) {\n            System.out.println((i + 1) + \". \" + topics.get(i));\n        }\n    }\n\n    public static void main(String[] args) {\n        // Module context first so the learner sees where this snippet fits.\n        String moduleTitle = \"Montones y colas prioritarias\";\n        String moduleDescription = \"Primero, `priorityQueueDemo` muestra el montÃ³n mÃ­nimo de la biblioteca, luego `heapify`/`buildMinHeap` reconstruye la estructura a partir de una matriz para que pueda rastrear las matemÃ¡ticas de Ã­ndice, los intercambios y la construcciÃ³n del montÃ³n ascendente.\";\n        String focusTopic = \"Colas prioritarias\";\n        List<String> topics = Arrays.asList(\"MontÃ³n mÃ­nimo\", \"MontÃ³n mÃ¡ximo\", \"Operaciones de montÃ³n\", \"Heapify\", \"Colas prioritarias\");\n\n        System.out.println(\"Module: \" + moduleTitle);\n        System.out.println(\"Focus topic (5/5): \" + focusTopic);\n        System.out.println(moduleDescription);\n\n        // Print all module topics so this split example stays connected to the full module.\n        System.out.println(\"1. Min Heap\");\n        System.out.println(\"2. Max Heap\");\n        System.out.println(\"3. Heap Operations\");\n        System.out.println(\"4. Heapify\");\n        System.out.println(\"5. Priority Queues\");\n\n        // Guided computation with explicit checkpoints and visible output.\n        int baseline = 15;\n        System.out.println(\"Baseline value: \" + baseline);\n        int result = guidedComputation(baseline);\n        System.out.println(\"Final computed result: \" + result);\n\n        // Reflection prompts are printed so output is always meaningful.\n        System.out.println(\"Reflection: explain how \" + focusTopic + \" influences implementation choices.\");\n        System.out.println(\"Practice: modify baseline, rerun, and compare output transitions.\");\n\n        // Summary line makes expected output deterministic for fallbacks.\n        System.out.println(\"Topic sample completed: \" + focusTopic);\n    }\n}",
              "cpp": "#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\n\nint main() {\n    // Espejo C++ del ejemplo del mÃ³dulo Java actualizado.\n    string moduleTitle = \"Heaps and Priority Queues â€¢ Priority Queues\";\n    string moduleDescription = \"Primero, `priorityQueueDemo` muestra el montÃ³n mÃ­nimo de la biblioteca, luego `heapify`/`buildMinHeap` reconstruye la estructura a partir de una matriz para que pueda rastrear las matemÃ¡ticas de Ã­ndice, los intercambios y la construcciÃ³n del montÃ³n ascendente.\";\n    vector<string> topics = {\"MontÃ³n mÃ­nimo\", \"MontÃ³n mÃ¡ximo\", \"Operaciones de montÃ³n\", \"Heapify\", \"Colas prioritarias\"};\n    vector<string> javaSignals = {\"Lista de verificaciÃ³n de temas:\", \"1. Min Heap\", \"2. Max Heap\", \"3. Heap Operations\", \"4. Heapify\", \"5. Priority Queues\"};\n\n    // 1) Contexto del mÃ³dulo de alto nivel\n    cout << \"MÃ³dulo en ejecuciÃ³n: \" << moduleTitle << \"\\n\";\n    cout << moduleDescription << \"\\n\";\n\n    // 2) Lista de verificaciÃ³n de temas para garantizar una cobertura conceptual completa\n    cout << \"Lista de verificaciÃ³n de temas:\\n\";\n    for (size_t i = 0; i < topics.size(); i++) {\n        cout << \"- \" << topics[i] << \"\\n\";\n    }\n\n    // 3) Marcadores de paridad de Java (reflejan importantes puntos de control de salida de Java)\n    cout << \"Puntos de control de paridad del ejemplo de Java:\\n\";\n    for (const auto& line : javaSignals) {\n        cout << \"* \" << line << \"\\n\";\n    }\n\n    cout << \"Muestra de paridad de C++ completada.\\n\";\n    return 0;\n}",
              "python": "# Espejo de Python del ejemplo del mÃ³dulo Java actualizado.\n# Este guiÃ³n mantiene los mismos puntos de control conceptuales y los imprime claramente.\n\ndef run_module_demo():\n    module_title = \"Heaps and Priority Queues â€¢ Priority Queues\"\n    module_description = \"Primero, `priorityQueueDemo` muestra el montÃ³n mÃ­nimo de la biblioteca, luego `heapify`/`buildMinHeap` reconstruye la estructura a partir de una matriz para que pueda rastrear las matemÃ¡ticas de Ã­ndice, los intercambios y la construcciÃ³n del montÃ³n ascendente.\"\n    topics = [\"MontÃ³n mÃ­nimo\", \"MontÃ³n mÃ¡ximo\", \"Operaciones de montÃ³n\", \"Heapify\", \"Colas prioritarias\"]\n    java_signals = [\"Lista de verificaciÃ³n de temas:\", \"1. Min Heap\", \"2. Max Heap\", \"3. Heap Operations\", \"4. Heapify\", \"5. Priority Queues\"]\n\n    # 1) Contexto del mÃ³dulo de alto nivel\n    print(f\"MÃ³dulo en ejecuciÃ³n: {module_title}\")\n    print(module_description)\n\n    # 2) Lista de verificaciÃ³n de temas para una cobertura completa\n    print(\"Lista de verificaciÃ³n de temas:\")\n    for topic in topics:\n        print(f\"- {topic}\")\n\n    # 3) Marcadores de paridad de Java para confirmar la intenciÃ³n alineada\n    print(\"Puntos de control de paridad del ejemplo de Java:\")\n    for line in java_signals:\n        print(f\"* {lÃ­nea}\")\n\n    print(\"Muestra de paridad de Python completada.\")\n\nif __name__ == \"__main__\":\n    run_module_demo()\n",
