          "java": "/*\n * Algoritmos de grÃ¡ficos: muestra guiada completa\n * Objetivos de cobertura:\n * 1) RepresentaciÃ³n grÃ¡fica\n * 2) DFS\n * 3) BFS\n * 4) Camino mÃ¡s corto\n * 5) Ãrbol de expansiÃ³n mÃ­nimo\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\n// Recorrido del grÃ¡fico y camino mÃ¡s corto de Dijkstra\nimport java.util.*;\n\nclass Graph {\n    private final Map<Integer, List<int[]>> adjacency = new HashMap<>();\n\n    public void addEdge(int from, int to, int weight) {\n        adjacency.computeIfAbsent(from, k -> new ArrayList<>()).add(new int[]{to, weight});\n        adjacency.computeIfAbsent(to, k -> new ArrayList<>());\n    }\n\n    public void bfs(int start) {\n        Set<Integer> visited = new HashSet<>();\n        Queue<Integer> queue = new ArrayDeque<>();\n        queue.offer(start);\n        visited.add(start);\n        while (!queue.isEmpty()) {\n            int current = queue.poll();\n            System.out.print(current + \" \");\n            for (int[] edge : adjacency.getOrDefault(current, Collections.emptyList())) {\n                int neighbor = edge[0];\n                if (visited.add(neighbor)) {\n                    queue.offer(neighbor);\n                }\n            }\n        }\n        System.out.println();\n    }\n\n    public Map<Integer, Integer> dijkstra(int source) {\n        Map<Integer, Integer> dist = new HashMap<>();\n        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[1]));\n        pq.offer(new int[]{source, 0});\n        dist.put(source, 0);\n        while (!pq.isEmpty()) {\n            int[] current = pq.poll();\n            int node = current[0];\n            int distance = current[1];\n            if (distance > dist.getOrDefault(node, Integer.MAX_VALUE)) continue;\n            for (int[] edge : adjacency.getOrDefault(node, Collections.emptyList())) {\n                int neighbor = edge[0];\n                int weight = edge[1];\n                int newDist = distance + weight;\n                if (newDist < dist.getOrDefault(neighbor, Integer.MAX_VALUE)) {\n                    dist.put(neighbor, newDist);\n                    pq.offer(new int[]{neighbor, newDist});\n                }\n            }\n        }\n        return dist;\n    }\n\n    public static void main(String[] args) {\n        Graph graph = new Graph();\n        graph.addEdge(0, 1, 4);\n        graph.addEdge(0, 2, 1);\n        graph.addEdge(2, 1, 2);\n        graph.addEdge(1, 3, 1);\n        graph.addEdge(2, 3, 5);\n        System.out.print(\"BFS: \");\n        graph.bfs(0);\n        System.out.println(\"Distancias de Dijkstra desde 0: \" + graph.dijkstra(0));\n    }\n}",
