        "codeExamples": {
          "java": "/*\n * Conjuntos, relaciones y funciones: muestra guiada completa\n * Objetivos de cobertura:\n * 1) Establecer operaciones\n * 2) Producto cartesiano\n * 3) Relaciones\n * 4) Funciones Inyectivas\n * 5) Funciones sobreyectivas\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\n// Mini demostraciÃ³n de conjuntos, relaciones y funciones\nimport java.util.*;\n\npublic class SetsRelationsFunctions {\n    static boolean isInjective(Map<Integer, Integer> f) {\n        Set<Integer> seen = new HashSet<>();\n        for (int value : f.values()) {\n            if (!seen.add(value)) return false;\n        }\n        return true;\n    }\n\n    public static void main(String[] args) {\n        Set<Integer> a = new HashSet<>(Arrays.asList(1, 2, 3));\n        Set<Integer> b = new HashSet<>(Arrays.asList(3, 4, 5));\n        Set<Integer> intersection = new HashSet<>(a);\n        intersection.retainAll(b);\n        Set<Integer> union = new HashSet<>(a);\n        union.addAll(b);\n\n        Map<Integer, Integer> f = new HashMap<>();\n        f.put(1, 10); f.put(2, 20); f.put(3, 30);\n\n        System.out.println(\"A ? B = \" + intersection);\n        System.out.println(\"A ? B = \" + union);\n        System.out.println(\"f es inyectiva? \" + isInjective(f));\n    }\n}",
          "cpp": "// Mini demostraciÃ³n de conjuntos, relaciones y funciones\n#include <iostream>\n#include <set>\n#include <map>\nusing namespace std;\n\nbool isInjective(const map<int, int>& f) {\n    set<int> seen;\n    for (const auto& [k, v] : f) {\n        if (!seen.insert(v).second) return false;\n    }\n    return true;\n}\n\nint main() {\n    set<int> A = {1, 2, 3};\n    set<int> B = {3, 4, 5};\n    set<int> intersection, uni = A;\n    for (int x : B) {\n        if (A.count(x)) intersection.insert(x);\n        uni.insert(x);\n    }\n    map<int, int> f = {{1, 10}, {2, 20}, {3, 30}};\n\n    cout << \"A ? TamaÃ±o B = \" << intersection.size() << \"\\n\";\n    cout << \"A ? TamaÃ±o B = \" << uni.size() << \"\\n\";\n    cout << boolalpha << \"f es inyectiva? \" << isInjective(f) << \"\\n\";\n    return 0;\n}",
          "python": "# Mini demostraciÃ³n de conjuntos, relaciones y funciones\ndef is_injective(mapping):\n    return len(set(mapping.values())) == len(mapping.values())\n\nA = {1, 2, 3}\nB = {3, 4, 5}\nf = {1: 10, 2: 20, 3: 30}\n\nprint(\"A ? B =\", A & B)\nprint(\"A ? B =\", A | B)\nprint(\"f es inyectiva?\", is_injective(f))",
          "javascript": "// Mini demostraciÃ³n de conjuntos, relaciones y funciones\nconst A = new Set([1, 2, 3]);\nconst B = new Set([3, 4, 5]);\nconst intersection = [...A].filter((x) => B.has(x));\nconst union = new Set([...A, ...B]);\nconst f = new Map([[1, 10], [2, 20], [3, 30]]);\n\nconst values = [...f.values()];\nconst isInjective = new Set(values).size === values.length;\n\nconsole.log(\"A ? B =\", intersection);\nconsole.log(\"A ? B =\", [...union]);\nconsole.log(\"f es inyectiva?\", isInjective);"
        },
