              "assembly": "; Assembly Registers and Memory Basics - CPU Registers\n; Topic 1 of 5\n; Guided assembly sample for module-card viewing and output fallback notes.\n; Goal: trace registers, memory changes, and branch flow step by step.\n; Focus checklist:\n; 1) Initialize registers safely\n; 2) Execute deterministic operations\n; 3) Observe control flow and exit cleanly\n\nsection .data\n    out_msg db \"Assembly topic: CPU Registers\", 10\n    out_len equ $ - out_msg\n\nsection .text\n    global _start\n_start:\n    ; Initialize registers\n    xor rax, rax\n    mov rbx, 2\n    add rax, rbx\n\n    ; Print topic message (Linux syscall write)\n    mov rax, 1\n    mov rdi, 1\n    mov rsi, out_msg\n    mov rdx, out_len\n    syscall\n\n    ; Exit (Linux syscall exit)\n    mov rax, 60\n    xor rdi, rdi\n    syscall\n"
