        "codeExamples": {
          "assembly": "; Arrays + strings + basic I/O (Linux, Intel syntax)\nsection .data\n    nums dd 3, 4, 5, 6\n    text db \"HELLO\", 0\n    out_msg db \"Suma de matriz y longitud de cadena calculadas\", 10\n    out_len equ $ - out_msg\n\nsection .text\n    global _start\n_start:\n    xor eax, eax          ; sum = 0\n    mov ecx, 4            ; count\n    mov rsi, nums         ; pointer to array\n.sum_loop:\n    add eax, [rsi]\n    add rsi, 4            ; next int32 element\n    loop .sum_loop\n\n    ; string length scan\n    mov rdi, text\n    xor ebx, ebx\n.len_loop:\n    cmp byte [rdi], 0\n    je .done\n    inc ebx\n    inc rdi\n    jmp .len_loop\n.done:\n    ; EAX = array sum, EBX = string length\n    ; Print completion message\n    mov rax, 1              ; write\n    mov rdi, 1              ; stdout\n    mov rsi, out_msg\n    mov rdx, out_len\n    syscall\n\n    ; Exit\n    mov rax, 60             ; exit\n    xor rdi, rdi\n    syscall\n",
          "java": "/*\n * Conjuntos de ensamblaje, cadenas y E/S bÃ¡sicas: muestra guiada completa\n * Objetivos de cobertura:\n * 1) AritmÃ©tica de punteros\n * 2) recorrido de matriz\n * 3) Cadenas terminadas en nulo\n * 4) Llamadas al sistema\n * 5) Acceso a bytes/palabras\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\n// Matrices, cadenas y E/S analÃ³gicas en Java\npublic class AssemblyArraysStringsIO {\n    public static void main(String[] args) {\n        int[] nums = {3, 4, 5, 6};\n        int sum = 0;\n        for (int value : nums) sum += value;\n\n        String text = \"HELLO\";\n        int length = text.length();\n\n        System.out.println(\"suma(nÃºms) = \" + sum);\n        System.out.println(\"longitud (texto) = \" + length);\n        System.out.println(\"DemostraciÃ³n de E/S completa.\");\n    }\n}",
          "cpp": "// Matrices, cadenas y E/S analÃ³gicas en C++\n#include <iostream>\n#include <string>\nusing namespace std;\n\nint main() {\n    int nums[] = {3, 4, 5, 6};\n    int sum = 0;\n    for (int value : nums) sum += value;\n\n    string text = \"HELLO\";\n    int length = static_cast<int>(text.size());\n\n    cout << \"suma(nÃºms) = \" << sum << \"\\n\";\n    cout << \"longitud (texto) = \" << length << \"\\n\";\n    cout << \"DemostraciÃ³n de E/S completa.\\n\";\n    return 0;\n}",
          "python": "# Matrices, cadenas y entradas/salidas analÃ³gicas en Python\nnums = [3, 4, 5, 6]\nsum_value = sum(nums)\ntext = \"HELLO\"\nlength = len(text)\n\nprint(\"suma(nÃºms) =\", sum_value)\nprint(\"longitud (texto) =\", length)\nprint(\"DemostraciÃ³n de E/S completa.\")",
          "javascript": "// Matrices, cadenas y entradas/salidas analÃ³gicas en JavaScript\nconst nums = [3, 4, 5, 6];\nconst sumValue = nums.reduce((acc, value) => acc + value, 0);\nconst text = \"HELLO\";\nconst length = text.length;\n\nconsole.log(\"suma(nÃºms) =\", sumValue);\nconsole.log(\"longitud (texto) =\", length);\nconsole.log(\"DemostraciÃ³n de E/S completa.\");"
        },
