              "java": "/*\n * Fundamentos de Java: muestra guiada completa\n * Objetivos de cobertura:\n * 1) Variables\n * 2) Tipos de datos\n * 3) MÃ©todos\n * 4) clases\n * 5) Objetos\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\n// Variables in Java: declaration, mutation, and scope\npublic class VariablesDemo {\n    public static void main(String[] args) {\n        // 1) Primitive variable declarations\n        int age = 19;\n        double gpa = 3.85;\n        boolean enrolled = true;\n        char grade = 'A';\n\n        // 2) Reference variable declaration\n        String studentName = \"Jordan\";\n\n        // 3) Mutation / reassignment\n        age = age + 1; // birthday update\n        gpa = Math.round(gpa * 100.0) / 100.0;\n\n        // 4) Local scope example\n        {\n            int semesterCredits = 15;\n            System.out.println(\"Scoped credits: \" + semesterCredits);\n        }\n\n        // 5) Final output summary\n        System.out.println(\"Student: \" + studentName);\n        System.out.println(\"Age next year: \" + age);\n        System.out.println(\"GPA: \" + gpa);\n        System.out.println(\"Enrolled: \" + enrolled + \", grade target: \" + grade);\n    }\n}",
