              "java": "/*\n * ProgramaciÃ³n orientada a objetos: muestra guiada completa\n * Objetivos de cobertura:\n * 1) EncapsulaciÃ³n\n * 2) Herencia\n * 3) polimorfismo\n * 4) AbstracciÃ³n\n * 5) interfaces\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\n// Inheritance: subclass extends parent behavior\nclass Vehicle {\n    protected String brand;\n\n    Vehicle(String brand) {\n        this.brand = brand;\n    }\n\n    void start() {\n        System.out.println(brand + \" vehicle started.\");\n    }\n}\n\nclass Car extends Vehicle {\n    Car(String brand) {\n        super(brand);\n    }\n\n    void openTrunk() {\n        System.out.println(brand + \" trunk opened.\");\n    }\n}\n\npublic class InheritanceDemo {\n    public static void main(String[] args) {\n        Car car = new Car(\"Toyota\");\n        car.start();\n        car.openTrunk();\n    }\n}",
