          "java": "/*\n * Conectividad de bases de datos (JDBC): muestra guiada completa\n * Objetivos de cobertura:\n * 1) Controladores JDBC\n * 2) ConexiÃ³n\n * 3) DeclaraciÃ³n\n * 4) Conjunto de resultados\n * 5) Declaraciones preparadas\n * Estrategia de lectura:\n * - Siga los comentarios en lÃ­nea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida despuÃ©s de cada paso lÃ³gico.\n */\n// Ejemplo de JDBC\nimport java.sql.*;\n\npublic class JDBCExample {\n    private static final String URL = \"jdbc:mysql:// localhost:3306/escuela\";\n    private static final String USER = \"username\";\n    private static final String PASSWORD = \"password\";\n    \n    public static void getStudents() {\n        try (Connection conn = DriverManager.getConnection(URL, USER, PASSWORD);\n             Statement stmt = conn.createStatement();\n             ResultSet rs = stmt.executeQuery(\"SELECCIONAR * DE estudiantes\")) {\n            \n            while (rs.next()) {\n                System.out.println(\"IDENTIFICACIÃ“N: \" + rs.getInt(\"id\") + \n                                 \", Nombre: \" + rs.getString(\"name\"));\n            }\n        } catch (SQLException e) {\n            System.out.println(\"Error de base de datos: \" + e.getMessage());\n        }\n    }\n    \n    public static void insertStudent(String name, int age) {\n        String sql = \"INSERTAR EN estudiantes (nombre, edad) VALORES (?, ?)\";\n        try (Connection conn = DriverManager.getConnection(URL, USER, PASSWORD);\n             PreparedStatement pstmt = conn.prepareStatement(sql)) {\n            \n            pstmt.setString(1, name);\n            pstmt.setInt(2, age);\n            pstmt.executeUpdate();\n        } catch (SQLException e) {\n            System.out.println(\"Error al insertar estudiante: \" + e.getMessage());\n        }\n    }\n        }",
