              "javascript": "// Espejo de JavaScript del ejemplo del mÃ³dulo Java actualizado.\n// Esto conserva los mismos puntos de control de instrucciÃ³n y resultados visibles.\n(function runModuleDemo() {\n    const moduleTitle = \"Assembly Addressing Modes and Stack Frames â€¢ Local Variable Access\";\n    const moduleDescription = \"Lea y escriba memoria usando direccionamiento inmediato, de registro y de base+desplazamiento mientras comprende cÃ³mo los marcos de pila admiten llamadas a funciones.\";\n    const topics = [\"Modos Inmediato/Registro/Memoria\", \"Direccionamiento base + desplazamiento\", \"Marcos de pila\", \"Convenciones de llamada\", \"Acceso a variables locales\"];\n    const javaSignals = [\"Lista de verificaciÃ³n de temas:\", \"1. Immediate/Register/Memory Modes\", \"2. Base + Offset Addressing\", \"3. Stack Frames\", \"4. Call Conventions\", \"5. Local Variable Access\"];\n\n    // 1) Contexto del mÃ³dulo de alto nivel\n    console.log(\"MÃ³dulo en ejecuciÃ³n: \" + moduleTitle);\n    console.log(moduleDescription);\n\n    // 2) Lista de verificaciÃ³n de temas para una cobertura conceptual completa\n    console.log(\"Lista de verificaciÃ³n de temas:\");\n    topics.forEach((topic) => console.log(\"- \" + topic));\n\n    // 3) Marcadores de paridad de Java para alinearse con la muestra canÃ³nica de Java\n    console.log(\"Puntos de control de paridad del ejemplo de Java:\");\n    javaSignals.forEach((line) => console.log(\"* \" + line));\n\n    console.log(\"Muestra de paridad de JavaScript completada.\");\n})();\n",
              "assembly": "; Assembly Addressing Modes and Stack Frames - Local Variable Access\n; Topic 5 of 5\n; Guided assembly sample for module-card viewing and output fallback notes.\n; Goal: trace registers, memory changes, and branch flow step by step.\n; Focus checklist:\n; 1) Initialize registers safely\n; 2) Execute deterministic operations\n; 3) Observe control flow and exit cleanly\n\nsection .data\n    out_msg db \"Assembly topic: Local Variable Access\", 10\n    out_len equ $ - out_msg\n\nsection .text\n    global _start\n_start:\n    ; Initialize registers\n    xor rax, rax\n    mov rbx, 6\n    add rax, rbx\n\n    ; Print topic message (Linux syscall write)\n    mov rax, 1\n    mov rdi, 1\n    mov rsi, out_msg\n    mov rdx, out_len\n    syscall\n\n    ; Exit (Linux syscall exit)\n    mov rax, 60\n    xor rdi, rdi\n    syscall\n"
